# Approach: Vertical scan - compare char by char across all strings
# Time: O(S) total chars | Space: O(1)
def longestCommonPrefix(strs):
    if not strs: return ''
    for i in range(len(strs[0])):
        for s in strs[1:]:
            if i >= len(s) or s[i] != strs[0][i]:
                return strs[0][:i]
    return strs[0]

