# Approach: Backtracking with open/close count tracking
# Time: O(4^n/sqrt(n)) | Space: O(n)
def generateParenthesis(n):
    res = []
    def bt(s, op, cl):
        if len(s) == 2 * n:
            res.append(s); return
        if op < n: bt(s + '(', op + 1, cl)
        if cl < op: bt(s + ')', op, cl + 1)
    bt('', 0, 0)
    return res

